// ══════════════════════════════════════════════════════
// NŒUD 5 — Parser la réponse OpenAI
// Extrait : texte propre + bloc JSON analyse
// ══════════════════════════════════════════════════════

const openaiResponse = $input.first().json;
const promptData     = $('Préparer Prompt').first().json;

// ── Récupérer le texte brut de la réponse OpenAI ──────
const rawText = openaiResponse?.choices?.[0]?.message?.content || '';

if (!rawText) {
  return [{ json: {
    response_text: 'Sunny na pas pu répondre. Vérifiez la clé API OpenAI.',
    analyse_extraite: null,
    score_eau: null,
    alertes: promptData.alertes || [],
    planning: promptData.planning || {},
    conversation_id: promptData.conversation_id,
    callback_url:    promptData.callback_url
  }}];
}

// ── Extraire le bloc JSON en fin de réponse ────────────
// Cherche ```json ... ``` ou { "analyse": ... } directement
let analyseExtraite = null;
let scoreEau = null;
let responseText = rawText;

try {
  // Méthode 1 : bloc ```json ... ```
  const jsonMatch = rawText.match(/```json\s*([\s\S]*?)```/i);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[1].trim());
    analyseExtraite = parsed.analyse || null;
    scoreEau = parsed.score_eau ?? null;
    // Supprimer le bloc JSON du texte visible (garder seulement la prose)
    responseText = rawText.replace(/```json[\s\S]*?```/i, '').trim();
  } else {
    // Méthode 2 : JSON brut en fin de message
    const rawJsonMatch = rawText.match(/\{\s*"analyse"\s*:\s*\{[\s\S]*?\}\s*(?:,\s*"score_eau"[\s\S]*?)?\}/i);
    if (rawJsonMatch) {
      const parsed = JSON.parse(rawJsonMatch[0]);
      analyseExtraite = parsed.analyse || null;
      scoreEau = parsed.score_eau ?? null;
      responseText = rawText.replace(rawJsonMatch[0], '').trim();
    }
  }
} catch(e) {
  // JSON malformé : on garde le texte brut, pas d'analyse extraite
  analyseExtraite = null;
}

// ── Nettoyer le texte : retirer ```json orphelins ──────
responseText = responseText.replace(/```json|```/g, '').trim();

// ── Alertes enrichies avec l'analyse extraite ──────────
const alertes = [...(promptData.alertes || [])];
if (analyseExtraite) {
  const a = analyseExtraite;
  if (a.ph !== null && a.ph !== undefined) {
    if (a.ph < 7.0) alertes.push({urgence:'haute',   msg:'pH lu sur image : ' + a.ph + ' → trop bas, ajouter pH+'});
    if (a.ph > 7.6) alertes.push({urgence:'haute',   msg:'pH lu sur image : ' + a.ph + ' → trop élevé, corriger en premier'});
  }
  if (a.chlore !== null && a.chlore !== undefined && a.chlore < 0.5)
    alertes.push({urgence:'haute',   msg:'Chlore lu : ' + a.chlore + ' mg/L → désinfection insuffisante'});
  if (a.tac !== null && a.tac !== undefined && a.tac < 80)
    alertes.push({urgence:'moyenne', msg:'TAC lu : ' + a.tac + ' mg/L → pH instable'});
}

return [{ json: {
  response_text:    responseText,
  analyse_extraite: analyseExtraite,
  score_eau:        scoreEau,
  alertes:          alertes,
  planning:         promptData.planning || {},
  conversation_id:  promptData.conversation_id,
  callback_url:     promptData.callback_url,
  has_image:        promptData.has_image
}}];

